import React from "react";

export default function ColorPicker({ color, onChange }) {
  // This is a placeholder for a color wheel image or a real color picker library
  // For now, use the native color input, but style/position it as a color wheel
  return (
    <input
      type="color"
      className="color-picker"
      value={color}
      onChange={e => onChange(e.target.value)}
      aria-label="Pick a color"
      style={{ opacity: 0, cursor: "pointer" }} // Hide native UI, use overlay if you want a custom image
    />
  );
}
